import React, { useState } from 'react';
import './App.css';
import {
  Button,
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  CssBaseline,
  ThemeProvider,
  Dialog,
  DialogActions ,
  DialogContent,
  DialogContentText,
  DialogTitle
} from '@mui/material';
import { createTheme, makeStyles } from '@mui/material/styles'; // 确认导入
import {
  Menu as MenuIcon,
  GitHub as GitHubIcon,
  Info as InfoIcon,
  Brightness4 as Brightness4Icon,
  Brightness7 as Brightness7Icon,
  HomeRounded as HomeRoundedIcon
} from '@mui/icons-material';
import {
  amber,
  blue,
  blueGrey,
  brown,
  common,
  cyan,
  deepOrange,
  deepPurple,
  green,
  grey,
  indigo,
  lightBlue,
  lightGreen,
  lime,
  orange,
  pink,
  purple,
  red,
  teal,
  yellow
} from'@mui/material/colors';


function App() {
  const [drawerOpen, setDrawerOpen] = useState(false); // 管理Drawer的打开状态
  const [darkMode, setDarkMode] = useState(false); // 管理深色模式状态
  const [open, setOpen] = React.useState(false);

  const theme = createTheme({
    palette: {
      mode: darkMode ? 'dark' : 'light',
      primary: blue,
      secondary: {
        main: '#448aff',
      },
    },
  });

  const getGreeting = () => {
    const hour = new Date().getHours();
    return hour < 12 ? "早上好" : hour < 18 ? "下午好" : "晚上好";
  };

  const toggleDrawer = (open) => () => {
    setDrawerOpen(open);
  };

  const handleClickOpen = () => {
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
  };


  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <div className="App" style={{ backgroundColor: theme.palette.background.default, color: theme.palette.text.primary }}>
        <AppBar position="static">
          <Toolbar>
            <IconButton edge="start" sx={{ marginRight: 2 }} color="inherit" aria-label="menu" onClick={toggleDrawer(true)}>
              <MenuIcon />
            </IconButton>
            <Button href="#" color='inherit'>首页</Button>
            <Button href="#" color='inherit'>关于</Button>
            <div style={{ flexGrow: 1 }} />
            {/* 添加点击事件处理函数 */}
            <IconButton onClick={() => setDarkMode(prevMode => !prevMode)} color="inherit">
              {darkMode ? <Brightness7Icon /> : <Brightness4Icon />}
            </IconButton>
            <IconButton aria-label="GitHub" color="inherit" onClick={handleClickOpen}>
              <GitHubIcon />
            </IconButton>
          </Toolbar>

        </AppBar>

        <Typography variant="h4" sx={{ margin: 2 }}>
          {getGreeting()}，欢迎来到我的网站！
        </Typography>

        <Drawer anchor="left" open={drawerOpen} onClose={toggleDrawer(false)}>
          <List sx={{ width: 250 }}>
            <ListItem button onClick={toggleDrawer(false)}>
              <ListItemIcon>
                <HomeRoundedIcon color='success' />
              </ListItemIcon>
              <ListItemText primary="首页" />
            </ListItem>
            <ListItem button onClick={toggleDrawer(false)}>
              <ListItemIcon>
                <InfoIcon color='info' />
              </ListItemIcon>
              <ListItemText primary="关于" />
            </ListItem>
          </List>
        </Drawer>
        <Dialog
        open={open}
        onClose={handleClose}
        aria-labelledby="alert-dialog-title"
        aria-describedby="alert-dialog-description"
      >
        <DialogTitle id="alert-dialog-title">{"提示"}</DialogTitle>
        <DialogContent>
          <DialogContentText id="alert-dialog-description">
            你确定要离开吗？
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClose} color="primary">
            留下
          </Button>
          <Button href={"https://github.com/neverforward/"} color="primary" autoFocus>
            离开
          </Button>
        </DialogActions>
      </Dialog>

        <Button variant="contained">Hello World</Button>
      </div>
    </ThemeProvider>
  );
}

export default App;